/* ===== Page Wrapper ===== */
.map-wrapper {
  display: flex;
  flex-direction: column;
  gap: 24px;
  position: relative;
}

/* ===== Search Bar ===== */
.map-search-wrap {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 16px;
  flex-wrap: wrap;
}

.map-search-input {
  min-width: 300px;
  padding: 12px 16px;
  border-radius: 14px;
  border: 1px solid #5BADA8;
  font-size: 14px;
  outline: none;
}

.map-wrapper.light .map-search-input { background: #fff;    color: #333; }
.map-wrapper.dark  .map-search-input { background: #16213e; color: #eaeaea; }

/* ===== Map Container ===== */
.map-container-wrap { position: relative; }

.map-box {
  height: 520px;
  border-radius: 28px;
  overflow: hidden;
  border: 1px solid #5BADA8;
  position: relative;
}

.map-wrapper.light .map-box { background: #fff;    }
.map-wrapper.dark  .map-box { background: #0f3460; }

.map-inner { width: 100%; height: 100%; }

/* ===== Legend ===== */
.map-legend {
  position: absolute;
  top: 16px;
  right: 16px;
  border-radius: 12px;
  padding: 12px 16px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  z-index: 1000;
  font-size: 13px;
}

.map-wrapper.light .map-legend { background: rgba(255, 255, 255, 0.95); color: #333; }
.map-wrapper.dark  .map-legend { background: rgba(22, 33, 62, 0.9);    color: #eaeaea; }

.map-legend-title {
  font-weight: 700;
  margin-bottom: 8px;
  font-size: 14px;
}

.map-legend-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 6px;
}

.map-legend-row:last-child { margin-bottom: 0; }

/* ===== Listing Cards Grid ===== */
.map-cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 14px;
}

/* Shared card button */
.map-card-btn {
  padding: 18px;
  border-radius: 22px;
  text-align: left;
  cursor: pointer;
  transition: transform 0.2s;
  width: 100%;
}

.map-card-btn:hover { transform: translateY(-3px); }

