// ═══════════════════════════════════════════════════════════
// INITIALIZE STORAGE
// ═══════════════════════════════════════════════════════════
function initializeStorage() {
  if (!Storage.get(STORAGE_KEYS.conversations)) {
    Storage.set(STORAGE_KEYS.conversations, INITIAL_SHARED_CONVERSATIONS);
  }
  if (!Storage.get(STORAGE_KEYS.messages)) {
    Storage.set(STORAGE_KEYS.messages, INITIAL_SHARED_MESSAGES);
  }
}

// ═══════════════════════════════════════════════════════════
// TIMESTAMP HELPERS
// ═══════════════════════════════════════════════════════════
function formatTimestamp(timestamp) {
  if (!timestamp) return '';
  const now = Date.now();
  const diff = now - timestamp;
  const seconds = Math.floor(diff / 1000);
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);

  if (seconds < 60) return 'just now';
  if (minutes < 60) return `${minutes}m ago`;
  if (hours < 24) return `${hours}h ago`;
  if (days === 1) return 'yesterday';
  if (days < 7) return `${days}d ago`;

  return new Date(timestamp).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

function formatMessageTime(timestamp) {
  return new Date(timestamp).toLocaleTimeString('en-US', {
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  });
}

// ═══════════════════════════════════════════════════════════
// DESKTOP NOTIFICATIONS
// ═══════════════════════════════════════════════════════════
function requestNotificationPermission() {
  if ('Notification' in window && Notification.permission === 'default') {
    Notification.requestPermission();
  }
}

function showDesktopNotification(title, body) {
  if ('Notification' in window && Notification.permission === 'granted') {
    const notification = new Notification(title, { body, tag: `msg-${Date.now()}` });
    notification.onclick = () => { window.focus(); notification.close(); };
    setTimeout(() => notification.close(), 5000);
  }
}

// ═══════════════════════════════════════════════════════════
// STATUS HELPERS
// ═══════════════════════════════════════════════════════════
function getStatusIcon(status) {
  switch (status) {
    case 'sent':     return '✓';
    case 'delivered': return '✓✓';
    case 'read':     return '✓✓';
    default:         return '';
  }
}

function getStatusColor(status, darkMode) {
  if (status === 'read') return PRIMARY;
  if (status === 'delivered') return darkMode ? '#6b7280' : '#65676b';
  return darkMode ? '#4b5563' : '#aab1bd';
}

// ═══════════════════════════════════════════════════════════
// COMPONENTS
// ═══════════════════════════════════════════════════════════
function Avatar({ initials, size = 42, online = false, borderColor = '#16213e' }) {
  const colorIndex = (initials.charCodeAt(0) + (initials.charCodeAt(1) || 0)) % AVATAR_COLORS.length;

  return (
    <div className="avatar-wrapper" style={{ width: size, height: size }}>
      <div className="avatar-circle" style={{ width: size, height: size, background: AVATAR_COLORS[colorIndex], fontSize: size * 0.38 }}>
        {initials}
      </div>
      {online && <div className="avatar-online-dot" style={{ width: size * 0.35, height: size * 0.35, borderColor }} />}
    </div>
  );
}

function StatusIndicator({ status, darkMode }) {
  if (!status) return null;
  return (
    <span className="status-indicator" style={{ color: getStatusColor(status, darkMode) }}>
      {getStatusIcon(status)}
    </span>
  );
}

// ═══════════════════════════════════════════════════════════
// MAIN COMPONENT
// ═══════════════════════════════════════════════════════════
export default function Messaging({ darkMode = false, userType = 'tenant' }) {
  const role = userType;

  useEffect(() => {
    initializeStorage();
    requestNotificationPermission();
  }, []);

  // State from localStorage
  const [conversations, setConversations] = useState(() =>
    Storage.get(STORAGE_KEYS.conversations) || INITIAL_SHARED_CONVERSATIONS
  );
  const [allMessages, setAllMessages] = useState(() =>
    Storage.get(STORAGE_KEYS.messages) || INITIAL_SHARED_MESSAGES
  );

  // UI State
  const [selectedConvId, setSelectedConvId] = useState(1);
  const [searchQuery, setSearchQuery] = useState('');
  const [messageInput, setMessageInput] = useState('');
  const [notificationEnabled, setNotificationEnabled] = useState(
    Notification.permission === 'granted'
  );

  // Refs
  const messagesEndRef = useRef(null);
  const lastMessageIdRef = useRef(null);

  // Get role-specific data
  const roleConversations = conversations[role] || {};
  const roleMessages = allMessages[role] || {};
  const messages = roleMessages[selectedConvId] || [];
  const selectedConv = roleConversations[selectedConvId];

  // Auto-scroll to bottom
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [messages, scrollToBottom]);

  // ═══════════════════════════════════════════════════════════
  // CROSS-TAB SYNC via storage event
  // ═══════════════════════════════════════════════════════════
  useEffect(() => {
    const handleStorageChange = (e) => {
      if (!e.newValue) return;

      if (e.key === STORAGE_KEYS.conversations) {
        const newConversations = JSON.parse(e.newValue);
        setConversations(newConversations);

        // Show notification for new messages from other tab
        if (notificationEnabled) {
          const otherRole = role === 'tenant' ? 'landlord' : 'tenant';
          const newUnread = newConversations[role]?.[selectedConvId]?.unread || 0;
          const oldUnread = conversations[role]?.[selectedConvId]?.unread || 0;

          if (newUnread > oldUnread) {
            const convName = newConversations[role]?.[selectedConvId]?.name;
            const lastMsg = newConversations[role]?.[selectedConvId]?.lastMessage;
            if (convName && lastMsg) {
              showDesktopNotification(convName, lastMsg);
            }
          }
        }
      }

      if (e.key === STORAGE_KEYS.messages) {
        setAllMessages(JSON.parse(e.newValue));
      }
    };

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, [role, selectedConvId, notificationEnabled, conversations]);

  // ═══════════════════════════════════════════════════════════
  // SEND MESSAGE
  // ═══════════════════════════════════════════════════════════
  const sendMessage = useCallback(() => {
    if (!messageInput.trim() || !selectedConv) return;

    // Create new message
    const newMessage = {
      id: Date.now(),
      sender: 'sent',
      text: messageInput,
      timestamp: Date.now(),
      status: 'sent',
    };

    // Update messages
    const updatedMessages = [...messages, newMessage];
    const newAllMessages = { ...allMessages };
    newAllMessages[role] = { ...roleMessages, [selectedConvId]: updatedMessages };
    setAllMessages(newAllMessages);
    Storage.set(STORAGE_KEYS.messages, newAllMessages);

    // Update last message in conversation
    const updatedConversations = { ...conversations };
    updatedConversations[role][selectedConvId] = {
      ...selectedConv,
      lastMessage: messageInput,
      timestamp: Date.now(),
    };
    setConversations(updatedConversations);
    Storage.set(STORAGE_KEYS.conversations, updatedConversations);

    // Clear input
    setMessageInput('');

    // Show notification if enabled
    if (notificationEnabled) {
      showDesktopNotification('Message sent', messageInput.substring(0, 50));
    }

    // Mark as delivered after 1 second
    setTimeout(() => {
      const deliveredMessages = [...updatedMessages];
      const lastMsg = deliveredMessages[deliveredMessages.length - 1];
      if (lastMsg) {
        lastMsg.status = 'delivered';
        const finalAllMessages = { ...newAllMessages };
        finalAllMessages[role] = { ...roleMessages, [selectedConvId]: deliveredMessages };
        setAllMessages(finalAllMessages);
        Storage.set(STORAGE_KEYS.messages, finalAllMessages);
      }
    }, 1000);

    // Mark as read after 2 seconds
    setTimeout(() => {
      const readMessages = [...updatedMessages];
      const lastMsg = readMessages[readMessages.length - 1];
      if (lastMsg) {
        lastMsg.status = 'read';
        const finalAllMessages = { ...newAllMessages };
        finalAllMessages[role] = { ...roleMessages, [selectedConvId]: readMessages };
        setAllMessages(finalAllMessages);
        Storage.set(STORAGE_KEYS.messages, finalAllMessages);
      }
    }, 2000);
  }, [messageInput, selectedConv, selectedConvId, role, messages, allMessages, roleMessages, notificationEnabled]);

  // ═══════════════════════════════════════════════════════════
  // MARK AS READ when switching conversations
  // ═══════════════════════════════════════════════════════════
  useEffect(() => {
    if (selectedConv?.unread > 0) {
      setConversations((prev) => {
        const updated = {
          ...prev,
          [role]: {
            ...prev[role],
            [selectedConvId]: { ...prev[role][selectedConvId], unread: 0 },
          },
        };
        Storage.set(STORAGE_KEYS.conversations, updated);
        return updated;
      });
    }
  }, [selectedConvId, selectedConv?.unread, role]);

  // ═══════════════════════════════════════════════════════════
  // THEME TOKENS
  // ═══════════════════════════════════════════════════════════
  const c = {
    mainBg:          darkMode ? '#1a1a2e' : '#ffffff',
    sidebarBg:       darkMode ? '#16213e' : '#ffffff',
    chatBg:          darkMode ? '#16213e' : '#f5f5f5',
    inputBg:         darkMode ? '#0f3460' : '#f0f2f5',
    text:            darkMode ? '#ffffff' : '#1a1a1a',
    secondaryText:   darkMode ? '#a0a0b0' : '#65676b',
    receivedBubble:  darkMode ? '#1e3a5f' : '#e4e6eb',
    receivedText:    darkMode ? '#ffffff' : '#1a1a1a',
    sentBubble:       PRIMARY,
    sentText:        '#ffffff',
    activeConv:      PRIMARY,
    activeConvText:  '#ffffff',
    border:          darkMode ? '#2a2a4a' : '#e4e6eb',
    hoverBg:         darkMode ? '#1e2849' : '#f2f2f2',
  };

  const filteredConversations = Object.values(roleConversations).filter((conv) =>
    conv.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const toggleNotifications = () => {
    if (Notification.permission === 'granted') {
      setNotificationEnabled((prev) => !prev);
    } else {
      requestNotificationPermission();
    }
  };

  // ═══════════════════════════════════════════════════════════
  // RENDER
  // ═══════════════════════════════════════════════════════════
  return (
    <div className="messaging-wrapper" style={{ background: c.mainBg }}>

      {/* ── Sidebar ── */}
      <div className="messaging-sidebar" style={{ background: c.sidebarBg, borderRight: `1px solid ${c.border}` }}>

        <div className="messaging-sidebar__header" style={{ borderBottom: `1px solid ${c.border}` }}>
          <div className="messaging-sidebar__title-row">
            <h2 className="messaging-sidebar__title" style={{ color: c.text }}>Messages</h2>
            <button
              className="notification-toggle"
              onClick={toggleNotifications}
              title={notificationEnabled ? 'Disable notifications' : 'Enable notifications'}
              style={{ color: notificationEnabled ? PRIMARY : c.secondaryText }}
            >
              {notificationEnabled ? '' : ''}
            </button>
          </div>

          <input
            type="text"
            placeholder="Search conversations..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="messaging-sidebar__search"
            style={{ border: `1px solid ${c.border}`, background: c.inputBg, color: c.text }}
          />
        </div>

        <div className="messaging-sidebar__list">
          {filteredConversations.length === 0 ? (
            <div className="no-conversations" style={{ color: c.secondaryText }}>
              No conversations found
            </div>
          ) : (
            filteredConversations.map((conv) => {
              const isActive = selectedConvId === conv.id;
              return (
                <div
                  key={conv.id}
                  className="conv-item"
                  onClick={() => setSelectedConvId(conv.id)}
                  style={{
                    background: isActive ? c.activeConv : 'transparent',
                    borderBottom: `1px solid ${c.border}`,
                  }}
                  onMouseEnter={(e) => { if (!isActive) e.currentTarget.style.background = c.hoverBg; }}
                  onMouseLeave={(e) => { if (!isActive) e.currentTarget.style.background = 'transparent'; }}
                >
                  <Avatar initials={conv.avatar} size={48} online={conv.online} borderColor={c.sidebarBg} />

                  <div className="conv-item__body">
                    <div className="conv-item__top">
                      <span className="conv-item__name" style={{ fontWeight: conv.unread > 0 ? '700' : '600', color: isActive ? c.activeConvText : c.text }}>
                        {conv.name}
                      </span>
                      <span className="conv-item__time" style={{ color: isActive ? 'rgba(255,255,255,0.8)' : c.secondaryText }}>
                        {formatTimestamp(conv.timestamp)}
                      </span>
                    </div>

                    <div className="conv-item__bottom">
                      <p className="conv-item__preview" style={{ color: isActive ? 'rgba(255,255,255,0.8)' : c.secondaryText, fontWeight: conv.unread > 0 ? '600' : '400' }}>
                        {conv.lastMessage}
                      </p>
                      {conv.unread > 0 && (
                        <span className="conv-item__unread-badge" style={{ background: c.unreadDot || PRIMARY }}>
                          {conv.unread}
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>

      {/* ── Chat Window ── */}
      <div className="messaging-chat" style={{ background: c.chatBg }}>

        <div className="messaging-chat__header" style={{ borderBottom: `1px solid ${c.border}` }}>
          <Avatar initials={selectedConv?.avatar || 'XX'} size={40} online={selectedConv?.online} />
          <div className="messaging-chat__header-info">
            <h3 style={{ color: c.text }}>
              {selectedConv?.name}
              <span className="messaging-chat__header-role" style={{ color: c.secondaryText }}>
                {role === 'tenant' ? '(Landlord)' : '(Tenant)'}
              </span>
            </h3>
            <p className="messaging-chat__header-status" style={{ color: c.secondaryText }}>
              {selectedConv?.online ? 'Active now' : `Active ${formatTimestamp(selectedConv?.timestamp)}`}
            </p>
          </div>
        </div>

        {/* Messages */}
        <div className="messaging-chat__messages">
          {messages.map((msg, index) => {
            const isReceived = msg.sender === 'received';
            const showTimestamp = index === 0 ||
              (messages[index - 1]?.timestamp && msg.timestamp - messages[index - 1].timestamp > 300000);

            return (
              <div key={msg.id}>
                {showTimestamp && msg.timestamp && (
                  <div className="msg-timestamp" style={{ color: c.secondaryText }}>
                    {formatMessageTime(msg.timestamp)}
                  </div>
                )}
                <div className={`msg-row msg-row--${isReceived ? 'received' : 'sent'}`}>
                  {isReceived && <Avatar initials={selectedConv?.avatar || 'XX'} size={32} />}
                  <div className={`msg-bubble ${isReceived ? '' : 'msg-bubble--sent'}`} style={
                    isReceived
                      ? { background: c.receivedBubble, color: c.receivedText }
                      : { background: c.sentBubble, color: c.sentText }
                  }>
                    {msg.text}
                    {!isReceived && msg.status && (
                      <StatusIndicator status={msg.status} darkMode={darkMode} />
                    )}
                  </div>
                </div>
              </div>
            );
          })}
          <div ref={messagesEndRef} />
        </div>

        {/* Input area */}
        <div className="messaging-chat__input-area" style={{ borderTop: `1px solid ${c.border}` }}>
          <button className="input-icon-btn" style={{ background: c.inputBg }}></button>

          <input
            type="text"
            placeholder="Aa"
            value={messageInput}
            onChange={(e) => setMessageInput(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
            className="messaging-chat__text-input"
            style={{ border: `1px solid ${c.border}`, background: c.inputBg, color: c.text }}
          />

          <button className="input-icon-btn" style={{ background: c.inputBg, fontSize: '18px' }}></button>

          <button
            className="send-btn"
            onClick={sendMessage}
            disabled={!messageInput.trim()}
            style={{ opacity: messageInput.trim() ? 1 : 0.5 }}
          >
            ➤
          </button>
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { useBooking } from '../../../context/BookingContext';
import './Notifications.css';

const PRIMARY = '#E8622E';

const NOTIF_ICONS = {
  new_booking:      '',
  booking_accepted: '✅',
  booking_rejected: '❌',
  new_message:      '',
};

export default function Notifications({ darkMode = false, userType = 'tenant' }) {
  const { getNotifications, markNotificationRead, deleteNotification, clearAllNotifications } = useBooking();
  const dk = darkMode;

  const c = {
    text:          dk ? '#eaeaea'           : '#333',
    secondaryText: dk ? '#a0a0b0'           : '#666',
    cardBg:        dk ? '#16213e'           : '#fff',
    border:        dk ? '#2a2a4a'           : 'rgba(0,0,0,0.06)',
    unreadBg:      dk ? '#0f3460'           : '#fff8f0',
  };

  const notifications = getNotifications(userType);

  const formatTime = (iso) => {
    if (!iso) return '';
    const d    = new Date(iso);
    const diff = Date.now() - d;
    if (diff < 60_000)   return 'Just now';
    if (diff < 3_600_000) return `${Math.floor(diff / 60_000)}m ago`;
    if (diff < 86_400_000) return `${Math.floor(diff / 3_600_000)}h ago`;
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  const unreadCount = notifications.filter((n) => !n.read).length;

  return (
    <div>
      {/* ── Header ── */}
      <div className="notif-header">
        <h3 className="notif-header__title" style={{ color: c.text }}>
          {unreadCount > 0 && (
            <span className="notif-header__badge">{unreadCount} new</span>
          )}
        </h3>

        {notifications.length > 0 && (
          <button
            className="notif-header__clear-btn"
            onClick={() => clearAllNotifications(userType)}
            style={{ border: `1px solid ${c.border}`, color: c.secondaryText }}
            onMouseEnter={(e) => {
              e.currentTarget.style.borderColor = '#dc3545';
              e.currentTarget.style.color       = '#dc3545';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.borderColor = c.border;
              e.currentTarget.style.color       = c.secondaryText;
            }}
          >
             Clear All
          </button>
        )}
      </div>

      {/* ── Empty State ── */}
      {notifications.length === 0 ? (
        <div className="notif-empty" style={{ background: c.cardBg, color: c.secondaryText }}>
          <div className="notif-empty__icon"></div>
          <p className="notif-empty__text">No notifications yet.</p>
        </div>
      ) : (
        /* ── Notification List ── */
        <div className="notif-list">
          {notifications.map((notif) => (
            <div
              key={notif.id}
              className="notif-card"
              style={{
                background: notif.read ? c.cardBg : c.unreadBg,
                border: `1px solid ${notif.read ? c.border : PRIMARY}`,
              }}
            >
              {/* Icon */}
              <div className="notif-card__icon">
                {NOTIF_ICONS[notif.type] || ''}
              </div>

              {/* Body */}
              <div
                className={`notif-card__body ${notif.read ? 'notif-card__body--static' : 'notif-card__body--clickable'}`}
                onClick={() => { if (!notif.read) markNotificationRead(notif.id); }}
              >
                <div className="notif-card__top">
                  <h4 className="notif-card__title" style={{ color: c.text }}>
                    {notif.title}
                  </h4>
                  <span className="notif-card__time" style={{ color: c.secondaryText }}>
                    {formatTime(notif.createdAt)}
                  </span>
                </div>

                <p className="notif-card__message" style={{ color: c.secondaryText }}>
                  {notif.message}
                </p>

                {!notif.read && (
                  <span className="notif-card__read-hint">Click to mark as read</span>
                )}
              </div>

              {/* Delete */}
              <button
                className="notif-card__delete-btn"
                title="Delete notification"
                onClick={(e) => { e.stopPropagation(); deleteNotification(notif.id); }}
                style={{ color: c.secondaryText }}
                onMouseEnter={(e) => { e.currentTarget.style.color = '#dc3545'; }}
                onMouseLeave={(e) => { e.currentTarget.style.color = c.secondaryText; }}
              >
                ✕
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useBooking } from '../../../context/BookingContext';
import './Notifications.css';

const PRIMARY = '#E8622E';

const NOTIF_ICONS = {
  new_booking:      '',
  booking_accepted: '✅',
  booking_rejected: '❌',
  booking_cancelled: '❌',
  new_message:      '',
  tenant_removed:   '',
};

export default function Notifications({ darkMode = false, userType = 'tenant' }) {
  const { getNotifications, markNotificationRead, deleteNotification, clearAllNotifications, subscribeToNotifications } = useBooking();
  const [notifications, setNotifications] = useState([]);
  const dk = darkMode;

  const c = {
    text:          dk ? '#eaeaea'           : '#333',
    secondaryText: dk ? '#a0a0b0'           : '#666',
    cardBg:        dk ? '#16213e'           : '#fff',
    border:        dk ? '#2a2a4a'           : 'rgba(0,0,0,0.06)',
    unreadBg:      dk ? '#0f3460'           : '#fff8f0',
  };

  // Real-time notification updates
  useEffect(() => {
    const updateNotifications = () => {
      setNotifications(getNotifications(userType));
    };

    updateNotifications();
    const unsubscribe = subscribeToNotifications(updateNotifications);
    
    return () => unsubscribe();
  }, [userType, getNotifications, subscribeToNotifications]);

  const formatTime = (iso) => {
    if (!iso) return '';
    const d    = new Date(iso);
    const diff = Date.now() - d;
    if (diff < 60_000)   return 'Just now';
    if (diff < 3_600_000) return `${Math.floor(diff / 60_000)}m ago`;
    if (diff < 86_400_000) return `${Math.floor(diff / 3_600_000)}h ago`;
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  };

  const unreadCount = notifications.filter((n) => !n.read).length;

  return (
    <div>
      {/* ── Header ── */}
      <div className="notif-header">
        <h3 className="notif-header__title" style={{ color: c.text }}>
          {unreadCount > 0 && (
            <span className="notif-header__badge">{unreadCount} new</span>
          )}
        </h3>

        {notifications.length > 0 && (
          <button
            className="notif-header__clear-btn"
            onClick={() => { clearAllNotifications(userType); setNotifications([]); }}
            style={{ border: `1px solid ${c.border}`, color: c.secondaryText }}
            onMouseEnter={(e) => {
              e.currentTarget.style.borderColor = '#dc3545';
              e.currentTarget.style.color       = '#dc3545';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.borderColor = c.border;
              e.currentTarget.style.color       = c.secondaryText;
            }}
          >
             Clear All
          </button>
        )}
      </div>

      {/* ── Empty State ── */}
      {notifications.length === 0 ? (
        <div className="notif-empty" style={{ background: c.cardBg, color: c.secondaryText }}>
          <div className="notif-empty__icon"></div>
          <p className="notif-empty__text">No notifications yet.</p>
        </div>
      ) : (
        /* ── Notification List ── */
        <div className="notif-list">
          {notifications.map((notif) => (
            <div
              key={notif.id}
              className="notif-card"
              style={{
                background: notif.read ? c.cardBg : c.unreadBg,
                border: `1px solid ${notif.read ? c.border : PRIMARY}`,
              }}
            >
              {/* Icon */}
              <div className="notif-card__icon">
                {NOTIF_ICONS[notif.type] || ''}
              </div>

              {/* Body */}
              <div
                className={`notif-card__body ${notif.read ? 'notif-card__body--static' : 'notif-card__body--clickable'}`}
                onClick={() => { if (!notif.read) { markNotificationRead(notif.id); setNotifications(prev => prev.map(n => n.id === notif.id ? {...n, read: true} : n)); } }}
              >
                <div className="notif-card__top">
                  <h4 className="notif-card__title" style={{ color: c.text }}>
                    {notif.title}
                  </h4>
                  <span className="notif-card__time" style={{ color: c.secondaryText }}>
                    {formatTime(notif.createdAt)}
                  </span>
                </div>

                <p className="notif-card__message" style={{ color: c.secondaryText }}>
                  {notif.message}
                </p>

                {!notif.read && (
                  <span className="notif-card__read-hint">Click to mark as read</span>
                )}
              </div>

              {/* Delete */}
              <button
                className="notif-card__delete-btn"
                title="Delete notification"
                onClick={(e) => { e.stopPropagation(); deleteNotification(notif.id); setNotifications(prev => prev.filter(n => n.id !== notif.id)); }}
                style={{ color: c.secondaryText }}
                onMouseEnter={(e) => { e.currentTarget.style.color = '#dc3545'; }}
                onMouseLeave={(e) => { e.currentTarget.style.color = c.secondaryText; }}
              >
                ✕
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import React, { useState } from 'react';
import './Settings.css';

const PRIMARY = '#E8622E';

/* ─────────────────────────── Toggle ─────────────────────────── */
const Toggle = ({ checked, onChange }) => (
  <button
    type="button"
    className="toggle-btn"
    onClick={() => onChange(!checked)}
    style={{ background: checked ? PRIMARY : '#ddd' }}
  >
    <div
      className="toggle-btn__knob"
      style={{ left: checked ? '24px' : '2px' }}
    />
  </button>
);

/* ─────────────────────────── SettingRow ─────────────────────── */
const SettingRow = ({ label, control, colors }) => (
  <div
    className="setting-row"
    style={{ borderBottom: `1px solid ${colors.border}` }}
  >
    <label className="setting-row__label" style={{ color: colors.text }}>
      {label}
    </label>
    {control}
  </div>
);

/* ─────────────────────────── SettingSection ─────────────────── */
const SettingSection = ({ title, children, colors }) => (
  <div className="settings-section">
    <h3 className="settings-section__title" style={{ color: colors.text }}>
      {title}
    </h3>
    <div className="settings-section__body">{children}</div>
  </div>
);

/* ─────────────────────────── InputField ─────────────────────── */
const InputField = ({ label, type = 'text', value, onChange, placeholder, colors }) => (
  <div className="input-field">
    <label className="input-field__label" style={{ color: colors.secondaryText }}>
      {label}
    </label>
    <input
      type={type}
      value={value}
      onChange={onChange}
      placeholder={placeholder}
      className="input-field__input"
      style={{
        border: `1px solid ${colors.border}`,
        background: colors.inputBg,
        color: colors.text,
      }}
    />
  </div>
);

/* ─────────────────────────── Settings ───────────────────────── */
export default function Settings({ userType = 'tenant', darkMode = false, setDarkMode }) {
  const dk = darkMode;

  const colors = {
    cardBg:        dk ? '#16213e' : '#fff',
    text:          dk ? '#eaeaea' : '#333',
    secondaryText: dk ? '#a0a0b0' : '#666',
    border:        dk ? '#2a2a4a' : '#e8e8e8',
    inputBg:       dk ? '#0f3460' : '#fff',
    tabBg:         dk ? '#2a2a4a' : '#f0f0f0',
  };

  const isLandlord = userType === 'landlord';

  const [activeSettingTab, setActiveSettingTab] = useState('profile');

  // Load saved profile from localStorage on mount
  const savedProfile = (() => {
    try { return JSON.parse(localStorage.getItem('dormscout_landlord_profile') || '{}'); } catch (_) { return {}; }
  })();

  // Profile fields
  const [firstName,       setFirstName]       = useState(savedProfile.firstName       || '');
  const [lastName,        setLastName]         = useState(savedProfile.lastName        || '');
  const [email,           setEmail]            = useState(savedProfile.email           || '');
  const [phoneNumber,     setPhoneNumber]      = useState(savedProfile.phoneNumber     || '');
  const [university,      setUniversity]       = useState('');
  const [course,          setCourse]           = useState('');
  const [yearLevel,       setYearLevel]        = useState('');
  const [studentId,       setStudentId]        = useState('');
  const [currentPassword, setCurrentPassword]  = useState('');
  const [newPassword,     setNewPassword]      = useState('');
  const [confirmPassword, setConfirmPassword]  = useState('');
  const [businessName,    setBusinessName]     = useState(savedProfile.businessName    || '');
  const [businessPermit,  setBusinessPermit]   = useState(savedProfile.businessPermit  || '');
  const [isVerified,      setIsVerified]       = useState(savedProfile.isVerified      || false);

  // App settings
  const [emailNotifications, setEmailNotifications] = useState(true);
  const [inAppNotifications,  setInAppNotifications]  = useState(true);
  const [messageAlerts,       setMessageAlerts]       = useState(true);

  /* ── Helpers ── */
  const tabStyle = (tab) => ({
    background: activeSettingTab === tab ? PRIMARY : colors.tabBg,
    color:      activeSettingTab === tab ? '#fff'  : colors.text,
  });

  function saveLandlordProfile(extra = {}) {
    const profile = { firstName, lastName, email, phoneNumber, businessName, businessPermit, isVerified, ...extra };
    try { localStorage.setItem('dormscout_landlord_profile', JSON.stringify(profile)); } catch (_) {}
    window.dispatchEvent(new Event('dormscout:profileUpdated'));
  }

  function handleVerify() {
    if (!businessName.trim() || !businessPermit.trim()) {
      alert('Please fill in both Business Name and Business Permit Number before verifying.'); return;
    }
    setIsVerified(true);
    saveLandlordProfile({ isVerified: true });
    alert('Business verified successfully! ✓');
  }

  const UNIVERSITIES = [
    'Cebu Institute of Technology - University',
    'University of San Carlos - Downtown',
    'University of the Visayas',
    'University of Cebu - Main',
    'University of San Carlos - Talamban',
    'University of Cebu - Banilad',
    'University of Cebu - METC',
    'University of San Jose-Recoletos - Main',
    'University of San Jose-Recoletos - Basak',
    'Cebu Normal University',
    'University of the Philippines Cebu',
    'Southwestern University PHINMA',
    'Cebu Technological University',
    "Saint Theresa's College",
  ];

  /* ── Render ── */
  return (
    <div
      className="settings-wrapper"
      style={{ background: colors.cardBg, border: `1px solid ${colors.border}` }}
    >
      {/* ── Tabs ── */}
      <div className="settings-tabs">
        {[
          { key: 'profile',     label: 'Profile Settings' },
          { key: 'application', label: 'Application Settings' },
        ].map(({ key, label }) => (
          <button
            key={key}
            className="settings-tab-btn"
            style={tabStyle(key)}
            onClick={() => setActiveSettingTab(key)}
          >
            {label}
          </button>
        ))}
      </div>

      {/* ══════════════ PROFILE TAB ══════════════ */}
      {activeSettingTab === 'profile' && (
        <>
          {/* Profile Picture */}
          <SettingSection title="Profile Picture" colors={colors}>
            <div className="settings-avatar">
              <div className="settings-avatar__circle">??</div>
              <div>
                <p className="settings-avatar__hint" style={{ color: colors.secondaryText }}>
                  Click the avatar to upload a new profile picture.
                </p>
                <button className="btn-primary">Upload Profile</button>
              </div>
            </div>
          </SettingSection>

          {/* Personal Information */}
          <SettingSection title="Personal Information" colors={colors}>
            <div className="settings-grid-2 settings-grid-2--mb">
              <InputField label="First Name"   value={firstName}   onChange={(e) => setFirstName(e.target.value)}   placeholder="John"  colors={colors} />
              <InputField label="Last Name"    value={lastName}    onChange={(e) => setLastName(e.target.value)}    placeholder="Doe"   colors={colors} />
            </div>
            <div className="settings-grid-2">
              <InputField label="Email"        type="email" value={email}        onChange={(e) => setEmail(e.target.value)}        placeholder="john@example.com"   colors={colors} />
              <InputField label="Phone Number" type="tel"   value={phoneNumber}  onChange={(e) => setPhoneNumber(e.target.value)}  placeholder="+63 9XX XXX XXXX"   colors={colors} />
            </div>
            <button className="btn-primary btn-primary--mt" onClick={() => saveLandlordProfile()}>Save Changes</button>
          </SettingSection>

          {/* Landlord: Business Information */}
          {isLandlord && (
            <SettingSection title="Business Information" colors={colors}>
              {isVerified && (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px', padding: '8px 12px', background: 'rgba(34,197,94,0.1)', borderRadius: '8px', border: '1px solid rgba(34,197,94,0.3)' }}>
                  <span style={{ fontSize: '1.1rem' }}>✅</span>
                  <span style={{ color: '#16a34a', fontWeight: 700, fontSize: '0.9rem' }}>Verified Business</span>
                </div>
              )}
              <div className="settings-grid-2 settings-grid-2--mb">
                <InputField label="Business Name"          value={businessName}   onChange={(e) => setBusinessName(e.target.value)}   placeholder="Enter business name"   colors={colors} />
                <InputField label="Business Permit Number" value={businessPermit} onChange={(e) => setBusinessPermit(e.target.value)} placeholder="Enter permit number"    colors={colors} />
              </div>
              <p className="settings-verify-hint" style={{ color: colors.secondaryText }}>
                Fill in your business details to be verified as a legitimate landlord
              </p>
              <button className="btn-primary btn-primary--mt" onClick={handleVerify}>
                {isVerified ? '✓ Verified' : 'Verify'}
              </button>
            </SettingSection>
          )}

          {/* Tenant: Student Information */}
          {!isLandlord && (
            <SettingSection title="Student Information" colors={colors}>
              <div className="settings-grid-2 settings-grid-2--mb">
                {/* University select */}
                <div className="input-field">
                  <label className="input-field__label" style={{ color: colors.secondaryText }}>
                    University
                  </label>
                  <select
                    value={university}
                    onChange={(e) => setUniversity(e.target.value)}
                    className="input-field__select"
                    style={{
                      border: `1px solid ${colors.border}`,
                      background: colors.inputBg,
                      color: colors.text,
                    }}
                  >
                    <option value="">Select Your School</option>
                    {UNIVERSITIES.map((u) => (
                      <option key={u}>{u}</option>
                    ))}
                  </select>
                </div>

                <InputField label="Course" value={course} onChange={(e) => setCourse(e.target.value)} placeholder="Bachelor of Science in Computer Science" colors={colors} />
              </div>

              <div className="settings-grid-2">
                <InputField label="Year Level" value={yearLevel} onChange={(e) => setYearLevel(e.target.value)} placeholder="2nd Year / 3rd Year" colors={colors} />
                <InputField label="Student ID"  value={studentId}  onChange={(e) => setStudentId(e.target.value)}  placeholder="2024001234"          colors={colors} />
              </div>

              <button className="btn-primary btn-primary--mt">Save Changes</button>
            </SettingSection>
          )}

          {/* Change Password */}
          <SettingSection title="Change Password" colors={colors}>
            <div className="settings-password-field">
              <InputField label="Current Password"     type="password" value={currentPassword} onChange={(e) => setCurrentPassword(e.target.value)} placeholder="Enter your current password" colors={colors} />
            </div>
            <div className="settings-password-field">
              <InputField label="New Password"         type="password" value={newPassword}     onChange={(e) => setNewPassword(e.target.value)}     placeholder="Enter your new password"     colors={colors} />
            </div>
            <div className="settings-password-field">
              <InputField label="Confirm New Password" type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} placeholder="Confirm your new password"   colors={colors} />
            </div>
            <button className="btn-primary">Save Changes</button>
          </SettingSection>

          {/* Danger Zone */}
          <SettingSection title="Danger Zone" colors={colors}>
            <p className="settings-danger-text" style={{ color: colors.secondaryText }}>
              Once you delete your account, there is no going back. Please be certain.
            </p>
            <button className="btn-danger">Delete Account</button>
          </SettingSection>
        </>
      )}

      {/* ══════════════ APPLICATION TAB ══════════════ */}
      {activeSettingTab === 'application' && (
        <>
          <SettingSection title="Appearance" colors={colors}>
            <SettingRow
              label="Dark Mode"
              control={<Toggle checked={darkMode} onChange={setDarkMode} />}
              colors={colors}
            />
          </SettingSection>

          <SettingSection title="Notifications" colors={colors}>
            <SettingRow label="Email Notifications"  control={<Toggle checked={emailNotifications} onChange={setEmailNotifications} />} colors={colors} />
            <SettingRow label="In-App Notifications" control={<Toggle checked={inAppNotifications}  onChange={setInAppNotifications}  />} colors={colors} />
            <SettingRow label="New Message Alerts"   control={<Toggle checked={messageAlerts}       onChange={setMessageAlerts}       />} colors={colors} />
          </SettingSection>
        </>
      )}
    </div>
  );
}

