/* ─────────────────────────── Settings ───────────────────────── */
export default function Settings({ userType = 'tenant', darkMode = false, setDarkMode }) {
  const dk = darkMode;

  const colors = {
    cardBg:        dk ? '#16213e' : '#fff',
    text:          dk ? '#eaeaea' : '#333',
    secondaryText: dk ? '#a0a0b0' : '#666',
    border:        dk ? '#2a2a4a' : '#e8e8e8',
    inputBg:       dk ? '#0f3460' : '#fff',
    tabBg:         dk ? '#2a2a4a' : '#f0f0f0',
  };

  const isLandlord = userType === 'landlord';

  const [activeSettingTab, setActiveSettingTab] = useState('profile');
  const [saveSuccess, setSaveSuccess] = useState(false);

  // Load saved profile from localStorage on mount
  const savedProfile = (() => {
    try { return JSON.parse(localStorage.getItem('dormscout_landlord_profile') || '{}'); } catch (_) { return {}; }
  })();

  // Profile fields
  const [firstName,       setFirstName]       = useState(savedProfile.firstName       || '');
  const [lastName,        setLastName]         = useState(savedProfile.lastName        || '');
  const [email,           setEmail]            = useState(savedProfile.email           || '');
  const [phoneNumber,     setPhoneNumber]      = useState(savedProfile.phoneNumber     || '');
  const [businessName,    setBusinessName]     = useState(savedProfile.businessName    || '');
  const [businessPermit,  setBusinessPermit]   = useState(savedProfile.businessPermit  || '');
  const [isVerified,      setIsVerified]       = useState(savedProfile.isVerified      || false);
  const [emailNotifications, setEmailNotifications] = useState(true);
  const [inAppNotifications,  setInAppNotifications]  = useState(true);
  const [messageAlerts,       setMessageAlerts]       = useState(true);

  /* ── Helpers ── */
  const tabStyle = (tab) => ({
    background: activeSettingTab === tab ? '#E8622E' : colors.tabBg,
    color:      activeSettingTab === tab ? '#fff'  : colors.text,
  });

  function saveLandlordProfile(extra = {}) {
    const profile = { firstName, lastName, email, phoneNumber, businessName, businessPermit, isVerified, emailNotifications, inAppNotifications, messageAlerts, ...extra };
    try { 
      localStorage.setItem('dormscout_landlord_profile', JSON.stringify(profile));
      setSaveSuccess(true);
      setTimeout(() => setSaveSuccess(false), 3000);
      window.dispatchEvent(new Event('dormscout:profileUpdated'));
    } catch (_) {}
  }

  function handleVerify() {
    if (!businessName.trim() || !businessPermit.trim()) {
      alert('Please fill in both Business Name and Business Permit Number before verifying.'); return;
    }
    setIsVerified(true);
    saveLandlordProfile({ isVerified: true });
    alert('Business verified successfully! ✓');
  }

  const UNIVERSITIES = [
    'Cebu Institute of Technology - University',
    'University of San Carlos - Downtown',
    'University of the Visayas',
    'University of Cebu - Main',
    'University of San Carlos - Talamban',
    'University of Cebu - Banilad',
    'University of Cebu - METC',
    'University of San Jose-Recoletos - Main',
    'University of San Jose-Recoletos - Basak',
    'Cebu Normal University',
    'University of the Philippines Cebu',
    'Southwestern University PHINMA',
    'Cebu Technological University',
    "Saint Theresa's College",
  ];

  /* ── Render ── */
  return (
    <div
      className="settings-wrapper"
      style={{ background: colors.cardBg, border: `1px solid ${colors.border}` }}
    >
      {/* ── Tabs ── */}
      <div className="settings-tabs">
        {[
          { key: 'profile',     label: 'Profile Settings' },
          { key: 'application', label: 'Application Settings' },
        ].map(({ key, label }) => (
          <button
            key={key}
            className="settings-tab-btn"
            style={tabStyle(key)}
            onClick={() => setActiveSettingTab(key)}
          >
            {label}
          </button>
        ))}
      </div>

      {/* ══════════════ PROFILE TAB ══════════════ */}
      {activeSettingTab === 'profile' && (
        <>
          {/* Profile Picture */}
          <SettingSection title="Profile Picture" colors={colors}>
            <div className="settings-avatar">
              <div className="settings-avatar__circle">??</div>
              <div>
                <p className="settings-avatar__hint" style={{ color: colors.secondaryText }}>
                  Click the avatar to upload a new profile picture.
                </p>
                <button className="btn-primary">Upload Profile</button>
              </div>
            </div>
          </SettingSection>

          {/* Personal Information */}
          <SettingSection title="Personal Information" colors={colors}>
            <div className="settings-grid-2 settings-grid-2--mb">
              <InputField label="First Name"   value={firstName}   onChange={(e) => setFirstName(e.target.value)}   placeholder="John"  colors={colors} />
              <InputField label="Last Name"    value={lastName}    onChange={(e) => setLastName(e.target.value)}    placeholder="Doe"   colors={colors} />
            </div>
            <div className="settings-grid-2">
              <InputField label="Email"        type="email" value={email}        onChange={(e) => setEmail(e.target.value)}        placeholder="john@example.com"   colors={colors} />
              <InputField label="Phone Number" type="tel"   value={phoneNumber}  onChange={(e) => setPhoneNumber(e.target.value)}  placeholder="+63 9XX XXX XXXX"   colors={colors} />
            </div>
            <button className="btn-primary btn-primary--mt" onClick={() => saveLandlordProfile()}>Save Changes</button>
            {saveSuccess && <p className="settings-save-success" style={{ color: colors.text }}>Changes saved successfully!</p>}
          </SettingSection>

          {/* Landlord: Business Information */}
          {isLandlord && (
            <SettingSection title="Business Information" colors={colors}>
              {isVerified && (
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px', padding: '8px 12px', background: 'rgba(34,197,94,0.1)', borderRadius: '8px', border: '1px solid rgba(34,197,94,0.3)' }}>
                  <span style={{ fontSize: '1.1rem' }}>✅</span>
                  <span style={{ color: '#16a34a', fontWeight: 700, fontSize: '0.9rem' }}>Verified Business</span>
                </div>
              )}
              <div className="settings-grid-2 settings-grid-2--mb">
                <InputField label="Business Name"          value={businessName}   onChange={(e) => setBusinessName(e.target.value)}   placeholder="Enter business name"   colors={colors} />
                <InputField label="Business Permit Number" value={businessPermit} onChange={(e) => setBusinessPermit(e.target.value)} placeholder="Enter permit number"    colors={colors} />
              </div>
              <p className="settings-verify-hint" style={{ color: colors.secondaryText }}>
                Fill in your business details to be verified as a legitimate landlord
              </p>
              <button className="btn-primary btn-primary--mt" onClick={handleVerify}>
                {isVerified ? '✓ Verified' : 'Verify'}
              </button>
            </SettingSection>
          )}

          {/* Tenant: Student Information */}
          {!isLandlord && (
            <SettingSection title="Student Information" colors={colors}>
              <div className="settings-grid-2 settings-grid-2--mb">
                {/* University select */}
                <div className="input-field">
                  <label className="input-field__label" style={{ color: colors.secondaryText }}>
                    University
                  </label>
                  <select
                    value={university}
                    onChange={(e) => setUniversity(e.target.value)}
                    className="input-field__select"
                    style={{
                      border: `1px solid ${colors.border}`,
                      background: colors.inputBg,
                      color: colors.text,
                    }}
                  >
                    <option value="">Select Your School</option>
                    {UNIVERSITIES.map((u) => (
                      <option key={u}>{u}</option>
                    ))}
                  </select>
                </div>

                <InputField label="Course" value={course} onChange={(e) => setCourse(e.target.value)} placeholder="Bachelor of Science in Computer Science" colors={colors} />
              </div>

              <div className="settings-grid-2">
                <InputField label="Year Level" value={yearLevel} onChange={(e) => setYearLevel(e.target.value)} placeholder="2nd Year / 3rd Year" colors={colors} />
                <InputField label="Student ID"  value={studentId}  onChange={(e) => setStudentId(e.target.value)}  placeholder="2024001234"          colors={colors} />
              </div>

              <button className="btn-primary btn-primary--mt">Save Changes</button>
            </SettingSection>
          )}

          {/* Change Password */}
          <SettingSection title="Change Password" colors={colors}>
            <div className="settings-password-field">
              <InputField label="Current Password"     type="password" value={currentPassword} onChange={(e) => setCurrentPassword(e.target.value)} placeholder="Enter your current password" colors={colors} />
            </div>
            <div className="settings-password-field">
              <InputField label="New Password"         type="password" value={newPassword}     onChange={(e) => setNewPassword(e.target.value)}     placeholder="Enter your new password"     colors={colors} />
            </div>
            <div className="settings-password-field">
              <InputField label="Confirm New Password" type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} placeholder="Confirm your new password"   colors={colors} />
            </div>
            <button className="btn-primary">Save Changes</button>
          </SettingSection>

          {/* Danger Zone */}
          <SettingSection title="Danger Zone" colors={colors}>
            <p className="settings-danger-text" style={{ color: colors.secondaryText }}>
              Once you delete your account, there is no going back. Please be certain.
            </p>
            <button className="btn-danger">Delete Account</button>
          </SettingSection>
        </>
      )}

      {/* ══════════════ APPLICATION TAB ══════════════ */}
      {activeSettingTab === 'application' && (
        <>
          <SettingSection title="Appearance" colors={colors}>
            <SettingRow
              label="Dark Mode"
              control={<Toggle checked={darkMode} onChange={setDarkMode} />}
              colors={colors}
            />
          </SettingSection>

          <SettingSection title="Notifications" colors={colors}>
            <SettingRow label="Email Notifications"  control={<Toggle checked={emailNotifications} onChange={setEmailNotifications} />} colors={colors} />
            <SettingRow label="In-App Notifications" control={<Toggle checked={inAppNotifications}  onChange={setInAppNotifications}  />} colors={colors} />
            <SettingRow label="New Message Alerts"   control={<Toggle checked={messageAlerts}       onChange={setMessageAlerts}       />} colors={colors} />
          </SettingSection>
        </>
      )}
    </div>
  );
}

import React, { createContext, useContext, useState, useEffect } from 'react';

// --- LocalStorage Keys ---
const BOOKINGS_KEY = 'dormscout_bookings';
const NOTIFICATIONS_KEY = 'dormscout_notifications';
const MESSAGES_KEY = 'dormscout_chat_messages';
const TENANTS_KEY = 'dormscout_tenants';

// --- Mock current user data ---
const MOCK_TENANT = {
  id: 'tenant-1',
  name: 'Juan Dela Cruz',
  email: 'juan@email.com',
  phone: '0917-123-4567',
  avatar: 'JD',
  type: 'tenant',
};

const MOCK_LANDLORD = {
  id: 'landlord-1',
  name: 'Rosa Macaraeg',
  email: 'rosa@email.com',
  phone: '0918-987-6543',
  avatar: 'RM',
  type: 'landlord',
};

// --- Helper to load/save from localStorage ---
function loadJSON(key, fallback = []) {
  try {
    const raw = localStorage.getItem(key);
    return raw ? JSON.parse(raw) : fallback;
  } catch { return fallback; }
}
function saveJSON(key, data) {
  localStorage.setItem(key, JSON.stringify(data));
}

// --- Context ---
const BookingContext = createContext();

export function BookingProvider({ children }) {
  const [bookings, setBookings] = useState(() => loadJSON(BOOKINGS_KEY));
  const [notifications, setNotifications] = useState(() => loadJSON(NOTIFICATIONS_KEY));
  const [chatMessages, setChatMessages] = useState(() => loadJSON(MESSAGES_KEY, {}));
  const [tenants, setTenants] = useState(() => loadJSON(TENANTS_KEY));

  // Persist to localStorage on change
  useEffect(() => { saveJSON(BOOKINGS_KEY, bookings); }, [bookings]);
  useEffect(() => { saveJSON(NOTIFICATIONS_KEY, notifications); }, [notifications]);
  useEffect(() => { saveJSON(MESSAGES_KEY, chatMessages); }, [chatMessages]);
  useEffect(() => { saveJSON(TENANTS_KEY, tenants); }, [tenants]);

  // --- CREATE BOOKING (tenant action) ---
  function createBooking(listing, moveInDate) {
    const newBooking = {
      id: `booking-${Date.now()}`,
      listingId: listing.id,
      listingTitle: listing.title,
      listingAddress: listing.address,
      listingPrice: listing.price,
      listingDescription: listing.description,
      listingImages: listing.images || [],
      listingLat: listing.lat,
      listingLng: listing.lng,
      listingUniversity: listing.university,
      listingRooms: listing.availableRooms,
      listingTags: listing.tags || [],
      tenantId: MOCK_TENANT.id,
      tenantName: MOCK_TENANT.name,
      tenantEmail: MOCK_TENANT.email,
      tenantPhone: MOCK_TENANT.phone,
      tenantAvatar: MOCK_TENANT.avatar,
      moveInDate,
      status: 'pending', // pending | accepted | rejected
      createdAt: new Date().toISOString(),
    };
    setBookings(prev => [...prev, newBooking]);

    // Add notification for landlord
    addNotification({
      type: 'new_booking',
      title: 'New Booking Request',
      message: `${MOCK_TENANT.name} requested to book "${listing.title}" with move-in date ${moveInDate}`,
      bookingId: newBooking.id,
      listingId: listing.id,
      forRole: 'landlord',
    });

    return newBooking;
  }

  // --- ACCEPT BOOKING (landlord action) ---
  function acceptBooking(bookingId) {
    setBookings(prev => prev.map(b =>
      b.id === bookingId ? { ...b, status: 'accepted' } : b
    ));

    const booking = bookings.find(b => b.id === bookingId);
    if (booking) {
      // Add tenant to the listing's tenant list
      setTenants(prev => [...prev, {
        id: `tenant-record-${Date.now()}`,
        bookingId,
        listingId: booking.listingId,
        tenantId: booking.tenantId,
        tenantName: booking.tenantName,
        tenantEmail: booking.tenantEmail,
        tenantPhone: booking.tenantPhone,
        tenantAvatar: booking.tenantAvatar,
        roomNumber: `Room ${Math.floor(Math.random() * 20) + 1}`,
        moveInDate: booking.moveInDate,
        status: 'active',
      }]);

      // Notify tenant
      addNotification({
        type: 'booking_accepted',
        title: 'Booking Accepted!',
        message: `Your booking for "${booking.listingTitle}" has been accepted by the landlord.`,
        bookingId,
        listingId: booking.listingId,
        forRole: 'tenant',
      });
    }
  }

  // --- CANCEL BOOKING (tenant action) — removes tenant record + notifies both ---
  function cancelBooking(bookingId, reason, moveOutDate) {
    const booking = bookings.find(b => b.id === bookingId);
    setBookings(prev => prev.filter(b => b.id !== bookingId));
    setTenants(prev => prev.filter(t => t.bookingId !== bookingId));

    if (booking) {
      addNotification({
        type: 'booking_cancelled',
        title: 'Booking Cancelled',
        message: `${booking.tenantName} cancelled their booking for "${booking.listingTitle}".${reason ? ` Reason: ${reason}` : ''}${moveOutDate ? ` Move-out: ${moveOutDate}` : ''}`,
        bookingId,
        listingId: booking.listingId,
        forRole: 'landlord',
      });
      addNotification({
        type: 'booking_cancelled',
        title: 'Booking Cancelled',
        message: `You cancelled your booking for "${booking.listingTitle}".${reason ? ` Reason: ${reason}` : ''}`,
        bookingId,
        listingId: booking.listingId,
        forRole: 'tenant',
      });
    }
  }

  // --- REMOVE TENANT (landlord action) ---
  function removeTenant(tenantRecordId, reason, moveOutDate) {
    const tenantRecord = tenants.find(t => t.id === tenantRecordId);
    setTenants(prev => prev.filter(t => t.id !== tenantRecordId));

    if (tenantRecord) {
      // Remove the booking from context entirely
      setBookings(prev => prev.filter(b => b.id !== tenantRecord.bookingId));

      // Also remove the listing from tenant's dormscout_my_bookings localStorage
      try {
        const raw = localStorage.getItem('dormscout_my_bookings');
        const myBookings = raw ? JSON.parse(raw) : [];
        localStorage.setItem('dormscout_my_bookings', JSON.stringify(
          myBookings.filter(b => b.id !== tenantRecord.listingId)
        ));
      } catch (e) { /* ignore */ }
      addNotification({
        type: 'tenant_removed',
        title: 'Tenant Removed',
        message: `You have been removed from "${tenantRecord.listingId}".${reason ? ` Reason: ${reason}` : ''}${moveOutDate ? ` Move-out date: ${moveOutDate}` : ''}`,
        forRole: 'tenant',
      });
      addNotification({
        type: 'tenant_removed',
        title: 'Tenant Removed',
        message: `You removed ${tenantRecord.tenantName} from the listing.${reason ? ` Reason: ${reason}` : ''}${moveOutDate ? ` Move-out date: ${moveOutDate}` : ''}`,
        forRole: 'landlord',
      });
    }
  }

  // --- DELETE REJECTED BOOKING (landlord action — dismiss from list) ---
  function deleteRejectedBooking(bookingId) {
    setBookings(prev => prev.filter(b => b.id !== bookingId));
  }

  // --- REJECT BOOKING (landlord action) ---
  function rejectBooking(bookingId) {
    setBookings(prev => prev.map(b =>
      b.id === bookingId ? { ...b, status: 'rejected' } : b
    ));

    const booking = bookings.find(b => b.id === bookingId);
    if (booking) {
      addNotification({
        type: 'booking_rejected',
        title: 'Booking Rejected',
        message: `Your booking for "${booking.listingTitle}" has been rejected.`,
        bookingId,
        listingId: booking.listingId,
        forRole: 'tenant',
      });
    }
  }

  // --- ADD NOTIFICATION ---
  function addNotification(notif) {
    setNotifications(prev => [{
      id: `notif-${Date.now()}-${Math.random().toString(36).slice(2, 6)}`,
      ...notif,
      read: false,
      createdAt: new Date().toISOString(),
    }, ...prev]);
  }

  // --- MARK NOTIFICATION READ ---
  function markNotificationRead(notifId) {
    setNotifications(prev => prev.map(n =>
      n.id === notifId ? { ...n, read: true } : n
    ));
  }

  // --- DELETE NOTIFICATION ---
  function deleteNotification(notifId) {
    setNotifications(prev => prev.filter(n => n.id !== notifId));
  }

  // --- CLEAR ALL NOTIFICATIONS (for a role) ---
  function clearAllNotifications(role) {
    setNotifications(prev => prev.filter(n => n.forRole !== role));
  }

  // --- SEND CHAT MESSAGE ---
  function sendMessage(conversationId, senderRole, text) {
    const msg = {
      id: `msg-${Date.now()}`,
      sender: senderRole, // 'tenant' or 'landlord'
      text,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
      createdAt: new Date().toISOString(),
    };
    setChatMessages(prev => ({
      ...prev,
      [conversationId]: [...(prev[conversationId] || []), msg],
    }));

    // Notify the other party
    const otherRole = senderRole === 'tenant' ? 'landlord' : 'tenant';
    addNotification({
      type: 'new_message',
      title: 'New Message',
      message: `New message: "${text.substring(0, 50)}${text.length > 50 ? '...' : ''}"`,
      conversationId,
      forRole: otherRole,
    });
  }

  // --- HELPER: get bookings for a listing ---
  function getBookingsForListing(listingId) {
    return bookings.filter(b => b.listingId === listingId);
  }

  // --- HELPER: get pending count for a listing ---
  function getPendingCount(listingId) {
    return bookings.filter(b => b.listingId === listingId && b.status === 'pending').length;
  }

  // --- HELPER: get notifications for a role ---
  function getNotifications(role) {
    return notifications.filter(n => n.forRole === role);
  }

  function getUnreadCount(role) {
    return notifications.filter(n => n.forRole === role && !n.read).length;
  }

  // --- HELPER: get tenants for a listing ---
  function getTenantsForListing(listingId) {
    return tenants.filter(t => t.listingId === listingId);
  }

  return (
    <BookingContext.Provider value={{
      bookings,
      notifications,
      chatMessages,
      tenants,
      createBooking,
      acceptBooking,
      rejectBooking,
      cancelBooking,
      removeTenant,
      deleteRejectedBooking,
      addNotification,
      markNotificationRead,
      deleteNotification,
      clearAllNotifications,
      sendMessage,
      getBookingsForListing,
      getPendingCount,
      getNotifications,
      getUnreadCount,
      getTenantsForListing,
      MOCK_TENANT,
      MOCK_LANDLORD,
    }}>
      {children}
    </BookingContext.Provider>
  );
}

export function useBooking() {
  const ctx = useContext(BookingContext);
  if (!ctx) throw new Error('useBooking must be used within BookingProvider');
  return ctx;
}

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';

// --- LocalStorage Keys ---
